import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

describe("mergeIntervals", () => {
  // --- Empty / trivial cases ---

  it("returns [] for empty input", () => {
    // Catches: forgetting the empty-array base case (e.g. throwing or returning undefined).
    expect(mergeIntervals([])).toEqual([]);
  });

  it("returns a single interval unchanged", () => {
    // Catches: a merge loop that drops or duplicates the sole interval.
    expect(mergeIntervals([[1, 2]])).toEqual([[1, 2]]);
  });

  it("keeps a zero-width interval where start === end", () => {
    // Catches: treating start === end as invalid (spec allows start <= end).
    expect(mergeIntervals([[5, 5]])).toEqual([[5, 5]]);
  });

  // --- Overlap merging ---

  it("merges two overlapping intervals", () => {
    // Catches: failure to merge partial overlap ([1,4],[3,6] -> [1,6]).
    expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
  });

  it("keeps the larger end when one interval fully contains another", () => {
    // Off-by: using `end` instead of max(last.end, end) would shrink [1,10] to [1,3].
    expect(mergeIntervals([[1, 10], [2, 3]])).toEqual([[1, 10]]);
  });

  it("chains merges across three intervals that overlap transitively", () => {
    // Catches: comparing only against the original interval, not the running merged end.
    expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
  });

  // --- Touching vs disjoint boundary (the key threshold: start <= last.end) ---

  it("merges intervals that touch at a shared endpoint", () => {
    // Boundary AT the threshold: [1,2],[2,3] share endpoint 2 -> [1,3].
    expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
  });

  it("keeps intervals separate when there is a unit gap (just past touching)", () => {
    // Boundary JUST ABOVE: [1,2],[3,4] have a gap of 1 -> stay separate.
    expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
  });

  it("keeps clearly disjoint intervals separate", () => {
    // Catches: over-eager merging that collapses non-adjacent intervals.
    expect(mergeIntervals([[1, 2], [5, 8]])).toEqual([[1, 2], [5, 8]]);
  });

  // --- Sorting ---

  it("sorts output by start ascending regardless of input order", () => {
    // Catches: assuming pre-sorted input; unsorted [3,4],[1,2] must come out ordered.
    expect(mergeIntervals([[3, 4], [1, 2]])).toEqual([[1, 2], [3, 4]]);
  });

  it("merges intervals that overlap only after sorting", () => {
    // Catches: merging in input order — [5,7],[1,6] only merge once sorted -> [1,7].
    expect(mergeIntervals([[5, 7], [1, 6]])).toEqual([[1, 7]]);
  });

  it("handles a scrambled mix of overlapping and disjoint intervals", () => {
    // Hand-computed: sort -> [1,3],[2,6],[8,10],[15,18] -> [1,6],[8,10],[15,18].
    expect(
      mergeIntervals([[15, 18], [2, 6], [8, 10], [1, 3]])
    ).toEqual([[1, 6], [8, 10], [15, 18]]);
  });

  // --- Duplicates ---

  it("collapses identical duplicate intervals into one", () => {
    // Catches: duplicates surviving as separate entries.
    expect(mergeIntervals([[1, 2], [1, 2]])).toEqual([[1, 2]]);
  });

  // --- Negative and non-integer values ---

  it("merges intervals spanning negative coordinates", () => {
    // Catches: sort comparators or comparisons that assume non-negative numbers.
    expect(mergeIntervals([[-5, -1], [-3, 0]])).toEqual([[-5, 0]]);
  });

  it("does not merge non-integer intervals that fall just short of touching", () => {
    // Boundary JUST BELOW touching with floats: [1,1.5],[1.6,2] -> separate.
    expect(mergeIntervals([[1, 1.5], [1.6, 2]])).toEqual([[1, 1.5], [1.6, 2]]);
  });

  // --- Error handling: start > end ---

  it("throws RangeError when a pair has start > end", () => {
    // Boundary JUST ABOVE valid: start exceeds end by 1 -> must throw.
    expect(() => mergeIntervals([[3, 2]])).toThrow(RangeError);
  });

  it("does not throw when start === end (boundary of validity)", () => {
    // Boundary AT validity: start <= end is allowed, so [4,4] must not throw.
    expect(() => mergeIntervals([[4, 4]])).not.toThrow();
  });

  it("throws even when the invalid pair is not first", () => {
    // Catches: validating only the first element instead of every pair.
    expect(() => mergeIntervals([[1, 2], [9, 4]])).toThrow(RangeError);
  });

  // --- Immutability ---

  it("does not mutate the input array or its pairs", () => {
    // Catches: in-place sort/merge writing back into caller-owned arrays.
    const input = [[1, 10], [2, 3]];
    const snapshot = [[1, 10], [2, 3]];
    mergeIntervals(input);
    expect(input).toEqual(snapshot);
  });

  it("returns pairs that are not references into the input", () => {
    // Catches: returning the same inner arrays, so later mutation of output
    // corrupts the caller's data. Mutating the result must leave input intact.
    const input = [[1, 5]];
    const result = mergeIntervals(input);
    result[0][0] = 999;
    expect(input[0][0]).toBe(1);
  });
});

